/**
 * Climate panel operation mode (Schedule, Manual or Vacation)
 */
export type PanelMode = 'Schedule' | 'Manual' | 'Vacation';

/**
 * Calculation strategy for currentTemperature ('avg' is default)
 */
export type CalculationStrategy = 'avg' | 'min' | 'max' | 'median';

/**
 * Climate panel Heating/Cooling mode (Auto -> control heating and cooling, Heat -> only heating, Cool -> only cooling, Off -> system is turned off)
 */
export type Mode = 'Auto' | 'Heat' | 'Cool' | 'Off';

/**
 * Temperature settings for period of time
 */
export type ClimateSetpoint = {
    hour?: number;
    minute?: number;
    temperatureHeating?: number;
    temperatureCooling?: number;
};

